use super::is_active_model_behavior_impl;
use syn::File;
use syn::Item;
use syn::ItemEnum;
use syn::ItemImpl;
use syn::ItemStruct;
use syn::ItemUse;

pub(super) fn extract_active_model_behavior_impls(file: &File) -> impl Iterator<Item = &ItemImpl> {
    file.items.iter().filter_map(|item| match item {
        Item::Impl(item_impl) if is_active_model_behavior_impl(item_impl) => Some(item_impl),
        _ => None,
    })
}

pub(super) fn extract_top_level_uses(file: &File) -> impl Iterator<Item = &ItemUse> {
    file.items.iter().filter_map(|item| match item {
        Item::Use(item_use) => Some(item_use),
        _ => None,
    })
}

pub(super) fn find_model_struct(file: &File) -> Option<&ItemStruct> {
    file.items.iter().find_map(|item| {
        if let Item::Struct(item_struct) = item
            && item_struct.ident == "Model"
        {
            return Some(item_struct);
        }
        None
    })
}

pub(super) fn find_relation_enum(file: &File) -> Option<&ItemEnum> {
    file.items.iter().find_map(|item| {
        if let Item::Enum(item_enum) = item
            && item_enum.ident == "Relation"
        {
            return Some(item_enum);
        }
        None
    })
}

use super::SelectorTrait;
use crate::{ConnectionTrait, StatementBuilder, error::*};
use itertools::Itertools;
use std::marker::PhantomData;

#[derive(Clone, Debug)]
pub(super) struct ReturningSelector<S, Q>
where
    S: SelectorTrait,
    Q: StatementBuilder,
{
    pub(crate) query: Q,
    selector: PhantomData<S>,
}

impl<S, Q> ReturningSelector<S, Q>
where
    S: SelectorTrait,
    Q: StatementBuilder,
{
    pub fn from_query(query: Q) -> Self {
        Self {
            query,
            selector: PhantomData,
        }
    }

    pub fn one<C>(self, db: &C) -> Result<Option<S::Item>, DbErr>
    where
        C: ConnectionTrait,
    {
        let row = db.query_one(&self.query)?;
        match row {
            Some(row) => Ok(Some(S::from_raw_query_result(row)?)),
            None => Ok(None),
        }
    }

    pub fn all<C>(self, db: &C) -> Result<Vec<S::Item>, DbErr>
    where
        C: ConnectionTrait,
    {
        db.query_all(&self.query)?
            .into_iter()
            .map(|row| S::from_raw_query_result(row))
            .try_collect()
    }
}

use proc_macro2::TokenStream;
use quote::quote;
use syn::{
    Ident, LitStr, Token,
    parse::{Parse, ParseStream},
};

struct CallArgs {
    backend: Ident,
    _comma: Token![,],
    sql_string: LitStr,
}

impl Parse for CallArgs {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        Ok(CallArgs {
            backend: input.parse()?,
            _comma: input.parse()?,
            sql_string: input.parse()?,
        })
    }
}

pub fn expand(input: proc_macro::TokenStream) -> syn::Result<TokenStream> {
    let CallArgs {
        backend,
        sql_string,
        ..
    } = syn::parse(input)?;

    let builder = match backend.to_string().as_str() {
        "MySql" => quote!(MysqlQueryBuilder),
        "Postgres" => quote!(PostgresQueryBuilder),
        "Sqlite" => quote!(SqliteQueryBuilder),
        backend => panic!("Unsupported backend {backend}"),
    };

    Ok(quote! {{
        use sea_orm::sea_query;

        let query = sea_query::raw_query!(#builder, #sql_string);

        sea_orm::Statement {
            sql: query.sql,
            values: Some(query.values),
            db_backend: sea_orm::DbBackend::#backend,
        }
    }})
}

pub fn get_file_stem(path: &str) -> &str {
    std::path::Path::new(path)
        .file_stem()
        .map(|f| f.to_str().unwrap())
        .unwrap()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_get_file_stem() {
        let pair = vec![
            (
                "m20220101_000001_create_table.rs",
                "m20220101_000001_create_table",
            ),
            (
                "src/m20220101_000001_create_table.rs",
                "m20220101_000001_create_table",
            ),
            (
                "migration/src/m20220101_000001_create_table.rs",
                "m20220101_000001_create_table",
            ),
            (
                "/migration/src/m20220101_000001_create_table.tmp.rs",
                "m20220101_000001_create_table.tmp",
            ),
        ];
        for (path, expect) in pair {
            assert_eq!(get_file_stem(path), expect);
        }
    }
}

